import json

SCHEMA = {
    "vendor": str,
    "date": "ISO 8601",
    "total_amount": float,
    "line_items": list,
    "currency": "3-letter code"
}

def extract_with_schema(receipt_text: str) -> dict:
    """Schema-driven extraction with exception flagging."""
    result = {field: None for field in SCHEMA}
    exception_flags = []
    # Claude extraction call would populate result here
    # Validate types and flag ambiguities
    for field, expected_type in SCHEMA.items():
        val = result.get(field)
        if val is None:
            exception_flags.append({"field": field, "reason": "missing or ambiguous"})
    result["exception_flags"] = exception_flags
    return result

def compare_passes(no_schema: dict, with_schema: dict) -> list:
    """Return list of fields where outputs diverge."""
    return [k for k in with_schema if with_schema.get(k) != no_schema.get(k)]
